            elif not sub_category and not detail_key: # 返回整个主类别字典
                return base_dict
            else: # 如果仅提供了 sub_category，则返回该子类别的内容
                if isinstance(base_dict, dict):
                    return base_dict.get(sub_category, f"子类别 '{sub_category}' 在 '{category}' 中未找到。")
                else:
                    return base_dict
        except AttributeError:
            return f"类别 '{category}' 未找到或结构不符合预期。"
